import React from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, X, ThumbsUp, ThumbsDown, Sparkles, Flag, ChevronLeft, ChevronRight } from 'lucide-react';
import { useUserInteractions } from '../contexts/UserInteractionsContext';
import { useModel } from '../contexts/ModelContext';
import { useTwitch } from '../contexts/TwitchContext';
import { getOptimizedImageUrl } from '../utils';
import { trackLoopConversion } from '../utils/analytics';

const ShowcaseModal = ({ image, onClose, model, onNext, onPrev, hasNext, hasPrev }) => {
    const { rateShowcaseImage } = useModel();
    const { hidePost, isHidden } = useUserInteractions();
    const { personas } = useTwitch();
    const navigate = useNavigate();

    // Stability: Threshold logic and stable timestamp for render-pure calculations
    const ACTIVE_THRESHOLD_MS = 15 * 60 * 1000;

    const nowRef = React.useRef(Date.now());
    const now = nowRef.current;

    // Defensive check: If image is missing, don't render anything (or could render error state)
    if (!image) return null;

    // Auto close if hidden while open
    if (isHidden(image.id)) {
        // slightly delayed close if we just hid it? Or immediate?
        // If it's hidden, we shouldn't show it.
        // If the user *just* hid it, we probably want to show a toast and close.
        // But if we return null, it just disappears.
        onClose();
        return null;
    }

    // Keyboard Navigation
    // eslint-disable-next-line react-hooks/rules-of-hooks
    React.useEffect(() => {
        const handleKeyDown = (e) => {
            if (e.key === 'ArrowRight' && hasNext) onNext();
            if (e.key === 'ArrowLeft' && hasPrev) onPrev();
            if (e.key === 'Escape') onClose();
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [onNext, onPrev, hasNext, hasPrev, onClose]);

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 1000,
            background: 'var(--color-bg)',
            display: 'flex', flexDirection: 'column',
            animation: 'fadeIn 0.3s cubic-bezier(0.16, 1, 0.3, 1)'
        }}>
            {/* Top Bar */}
            <div style={{
                height: '60px', borderBottom: '1px solid var(--color-border)',
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '0 20px', background: 'var(--color-bg)'
            }}>
                <button
                    onClick={onClose}
                    className="flex-center"
                    style={{ gap: '8px', color: 'var(--color-text-muted)', fontSize: '0.9rem', fontWeight: '500', transition: 'color 0.2s', background: 'none', border: 'none', cursor: 'pointer' }}
                >
                    <ArrowLeft size={16} /> Back to Gallery
                </button>

                <div className="flex-center" style={{ gap: '12px' }}>
                    <button
                        onClick={() => {
                            hidePost(image);
                            onClose();
                        }}
                        className="btn-ghost"
                        title="Hide Post"
                        style={{ color: 'var(--color-text-muted)' }}
                    >
                        <Flag size={20} />
                    </button>
                    <button onClick={onClose} className="btn-ghost" title="Close" style={{ marginLeft: '12px' }}>
                        <X size={24} />
                    </button>
                </div>
            </div>

            {/* Split Layout */}
            <div style={{ display: 'flex', flex: 1, overflow: 'hidden' }}>

                {/* Image View */}
                <div style={{
                    flex: 1,
                    background: '#050505',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    padding: '40px',
                    position: 'relative'
                }}>
                    {/* Navigation Buttons (Overlay) */}
                    {hasPrev && (
                        <button
                            onClick={(e) => { e.stopPropagation(); onPrev(); }}
                            className="nav-btn-prev"
                            style={{
                                position: 'absolute', left: '20px', top: '50%', transform: 'translateY(-50%)',
                                background: 'rgba(0,0,0,0.5)', border: '1px solid rgba(255,255,255,0.1)',
                                borderRadius: '50%', width: '48px', height: '48px',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                color: 'white', cursor: 'pointer', zIndex: 10,
                                transition: 'all 0.2s hover:bg-white/20'
                            }}
                        >
                            <ChevronLeft size={28} />
                        </button>
                    )}

                    {hasNext && (
                        <button
                            onClick={(e) => { e.stopPropagation(); onNext(); }}
                            className="nav-btn-next"
                            style={{
                                position: 'absolute', right: '20px', top: '50%', transform: 'translateY(-50%)',
                                background: 'rgba(0,0,0,0.5)', border: '1px solid rgba(255,255,255,0.1)',
                                borderRadius: '50%', width: '48px', height: '48px',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                color: 'white', cursor: 'pointer', zIndex: 10,
                                transition: 'all 0.2s hover:bg-white/20'
                            }}
                        >
                            <ChevronRight size={28} />
                        </button>
                    )}

                    <img
                        src={getOptimizedImageUrl(image.imageUrl || image.url || image)}
                        alt={image.prompt ? `Showcase: ${image.prompt}` : "Model Showcase Detail"}
                        style={{
                            maxWidth: '100%', maxHeight: '100%',
                            boxShadow: '0 0 50px rgba(0,0,0,0.5)',
                            objectFit: 'contain'
                        }}
                    />
                </div>

                {/* Info Panel */}
                <div style={{
                    width: '400px',
                    borderLeft: '1px solid var(--color-border)',
                    background: 'var(--color-bg)',
                    overflowY: 'auto',
                    padding: '32px'
                }}>
                    <div style={{ marginBottom: '40px' }}>
                        <label className="meta-label">PROMPT</label>
                        <p style={{ fontSize: '1.1rem', lineHeight: '1.6', color: 'white', fontWeight: '400', fontStyle: 'italic', opacity: 0.8 }}>
                            {image.prompt ? `"${image.prompt}"` : `"This is a curated showcase generation demonstrating the capabilities of ${model?.name || 'this model'}. High-fidelity details and texture handling are key characteristics shown here."`}
                        </p>
                    </div>

                    {/* Ranking UI */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '40px' }}>
                        <button
                            onClick={() => {
                                const newRating = image.rating === 1 ? 0 : 1;
                                rateShowcaseImage(image.id, newRating, model?.id); // Safe model access
                            }}
                            className={`btn-ghost ${image.rating === 1 ? 'active-vote' : ''}`}
                            style={{
                                display: 'flex', alignItems: 'center', gap: '8px',
                                color: image.rating === 1 ? 'var(--color-accent-primary)' : 'var(--color-text-muted)',
                                background: image.rating === 1 ? 'rgba(79, 70, 229, 0.1)' : 'transparent',
                                padding: '8px 16px', borderRadius: '100px', border: '1px solid transparent',
                                borderColor: image.rating === 1 ? 'var(--color-accent-primary)' : 'rgba(255,255,255,0.1)',
                                transition: 'all 0.2s', cursor: 'pointer'
                            }}
                        >
                            <ThumbsUp size={16} fill={image.rating === 1 ? "currentColor" : "none"} />
                            <span style={{ fontSize: '0.8rem', fontWeight: '600' }}>Helpful</span>
                        </button>

                        <button
                            onClick={() => {
                                const newRating = image.rating === -1 ? 0 : -1;
                                rateShowcaseImage(image.id, newRating, model?.id); // Safe model access
                            }}
                            className={`btn-ghost ${image.rating === -1 ? 'active-vote' : ''}`}
                            style={{
                                display: 'flex', alignItems: 'center', gap: '8px',
                                color: image.rating === -1 ? '#ef4444' : 'var(--color-text-muted)',
                                background: image.rating === -1 ? 'rgba(239, 68, 68, 0.1)' : 'transparent',
                                padding: '8px 16px', borderRadius: '100px', border: '1px solid transparent',
                                borderColor: image.rating === -1 ? '#ef4444' : 'rgba(255,255,255,0.1)',
                                transition: 'all 0.2s', cursor: 'pointer'
                            }}
                        >
                            <ThumbsDown size={16} fill={image.rating === -1 ? "currentColor" : "none"} />
                        </button>
                    </div>

                    <div style={{ height: '1px', background: 'var(--color-border)', margin: '0 0 40px 0' }} />

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '32px 12px' }}>
                        <div>
                            <label className="meta-label">MODEL</label>
                            <div className="meta-value">{model?.name || 'Unknown'}</div>
                        </div>
                        <div>
                            <label className="meta-label">AESTHETIC</label>
                            <div className="meta-value">
                                {image.aesthetics?.quality || 'Standard'}
                                <span style={{ opacity: 0.5, fontSize: '0.8em', marginLeft: '6px' }}>
                                    {image.aesthetics?.score ? `${image.aesthetics.score}/10` : ''}
                                </span>
                            </div>
                        </div>

                        {/* New Metadata Display */}
                        {image.colors?.paletteName && (
                            <div className="col-span-2" style={{ gridColumn: 'span 2' }}>
                                <label className="meta-label">PALETTE</label>
                                <div className="meta-value flex items-center gap-2">
                                    {image.colors.paletteName}
                                    <div style={{ display: 'flex', gap: '4px', marginLeft: '8px' }}>
                                        {image.colors.dominant?.map((c, i) => (
                                            <div key={i} style={{ width: '12px', height: '12px', borderRadius: '50%', background: c, border: '1px solid rgba(255,255,255,0.2)' }} />
                                        ))}
                                    </div>
                                </div>
                            </div>
                        )}

                        {image.discovery?.vibeTags && (
                            <div className="col-span-2" style={{ gridColumn: 'span 2' }}>
                                <label className="meta-label">VIBE TAGS</label>
                                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                                    {image.discovery.vibeTags.map((tag, i) => (
                                        <span key={i} style={{
                                            background: 'rgba(255,255,255,0.1)',
                                            padding: '4px 8px',
                                            borderRadius: '4px',
                                            fontSize: '0.75rem'
                                        }}>
                                            {tag}
                                        </span>
                                    ))}
                                </div>
                            </div>
                        )}

                        {image.style?.primary && (
                            <div>
                                <label className="meta-label">STYLE</label>
                                <div className="meta-value">{image.style.primary}</div>
                            </div>
                        )}
                        {image.style?.subGenre && (
                            <div>
                                <label className="meta-label">GENRE</label>
                                <div className="meta-value">{image.style.subGenre}</div>
                            </div>
                        )}

                        <div>
                            <label className="meta-label">STEPS</label>
                            <div className="meta-value">{image.steps || 30}</div>
                        </div>
                        <div>
                            <label className="meta-label">GUIDANCE</label>
                            <div className="meta-value">{image.cfg || 7.0}</div>
                        </div>
                        <div>
                            <label className="meta-label">DIMENSIONS</label>
                            <div className="meta-value">{image.width && image.height ? `${image.width}x${image.height}` : '1024x1024'}</div>
                        </div>
                        <div>
                            <label className="meta-label">SCHEDULER</label>
                            <div className="meta-value">{image.scheduler || 'DPM++ 2M'}</div>
                        </div>
                    </div>

                    <div style={{ marginTop: '60px' }}>
                        <div className="p-4 rounded-lg border border-[var(--color-border)] bg-[rgba(255,255,255,0.03)]">
                            <h4 className="text-sm font-bold text-white mb-2 flex items-center gap-2">
                                <Sparkles size={14} className="text-[var(--color-accent-primary)]" />
                                INSPIRED?
                            </h4>
                            <p className="text-sm text-[var(--color-text-muted)] mb-4">
                                Activate this model engine to generate similar high-quality results.
                            </p>
                            <div style={{ display: 'flex', gap: '8px' }}>
                                <button
                                    onClick={() => {
                                        onClose();
                                        const params = new URLSearchParams();
                                        if (image.prompt) params.set('prompt', image.prompt);
                                        if (image.steps) params.set('steps', image.steps);
                                        if (image.cfg) params.set('cfg', image.cfg);
                                        if (image.aspectRatio) params.set('aspectRatio', image.aspectRatio);

                                        trackLoopConversion('showcase_start_creating', model?.id);
                                        navigate(`/generate?${params.toString()}`);
                                    }}
                                    className="btn btn-outline w-full justify-center text-xs"
                                    style={{ flex: 1 }}
                                >
                                    START CREATING
                                </button>
                                {(() => {
                                    const persona = personas.find(p => p.id === image.id);

                                    // Threshold Logic (Matches Backend: 15 mins)
                                    const activePersonas = personas.filter(p => {
                                        const lastActivity = p.lastActivity?.toMillis?.() || p.lastActivity?.seconds * 1000 || 0;
                                        return (now - lastActivity) < ACTIVE_THRESHOLD_MS;
                                    });

                                    const isSystemAtCapacity = activePersonas.length >= 5;
                                    const isTargetPersonaActive = persona && (now - (persona.lastActivity?.toMillis?.() || persona.lastActivity?.seconds * 1000 || 0)) < ACTIVE_THRESHOLD_MS;

                                    const shouldRedirectToBrowse = !isTargetPersonaActive && isSystemAtCapacity;

                                    return (
                                        <button
                                            onClick={() => {
                                                onClose();
                                                if (shouldRedirectToBrowse) {
                                                    navigate('/browse');
                                                } else {
                                                    trackLoopConversion('showcase_talk_to_picture', model?.id);
                                                    navigate(`/channel/${image.id}`, { state: { imageItem: image } });
                                                }
                                            }}
                                            className="btn w-full justify-center text-xs"
                                            title={shouldRedirectToBrowse ? "System at capacity. View active channels." : ""}
                                            style={{
                                                flex: 1,
                                                background: '#a970ff',
                                                color: 'white',
                                                border: 'none',
                                                fontWeight: '700',
                                                cursor: 'pointer'
                                            }}
                                        >
                                            {shouldRedirectToBrowse ? 'VIEW LIVE CHANNELS' : 'TALK TO A PICTURE'}
                                        </button>
                                    );
                                })()}
                            </div>
                        </div>
                    </div>

                </div>
            </div>
            <style>{`
                .meta-label {
                    font-size: 0.7rem;
                    font-weight: 700;
                    letter-spacing: 0.05em;
                    color: var(--color-text-dim);
                    text-transform: uppercase;
                    display: block;
                    margin-bottom: 8px;
                }
                .meta-value {
                    font-size: 0.95rem;
                    font-weight: 500;
                    color: white;
                }
                /* Mobile Responsiveness for Modal */
                @media (max-width: 768px) {
                    div[style*="display: flex; flex: 1"] {
                        flex-direction: column;
                        overflow-y: auto !important;
                    }
                    /* Image Container */
                    div[style*="background: #050505"] {
                        min-height: 400px;
                        padding: 20px !important;
                    }
                    /* Info Panel */
                    div[style*="width: 400px"] {
                        width: 100% !important;
                        border-left: none !important;
                        border-top: 1px solid var(--color-border);
                        padding: 20px !important;
                        overflow-y: visible !important;
                    }
                }
                @keyframes fadeIn {
                    from { opacity: 0; }
                    to { opacity: 1; }
                }
            `}</style>
        </div>
    );
};

ShowcaseModal.displayName = 'ShowcaseModal';

export default ShowcaseModal;

import React, { useState } from 'react';

import { Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import {
    Home, User, LayoutTemplate, Zap, Film, LayoutGrid, Settings, Hexagon,
    ChevronDown, ChevronRight, Compass,
    Package, Images, Smile, Sparkles, Shield, Trophy // Imported for Mockup and Meme features
} from 'lucide-react';

const CollapsibleGroup = ({ title, children, defaultOpen = true }) => {
    const [isOpen, setIsOpen] = useState(defaultOpen);

    return (
        <div className="nav-group">
            <button
                className="sidebar-group-header"
                onClick={() => setIsOpen(!isOpen)}
            >
                <span className="group-title-text">{title}</span>
                {isOpen ? <ChevronDown size={14} className="group-chevron" /> : <ChevronRight size={14} className="group-chevron" />}
            </button>
            <div className={`group-content ${isOpen ? 'open' : ''}`}>
                {children}
            </div>
        </div>
    );
};

const Sidebar = ({ activeId }) => {
    const { currentUser } = useAuth();
    const isAdmin = currentUser?.uid === 'prT9j3royVTstWLDDcKMoUOU7aQ2';

    // Primary Top Level
    const homeLink = { path: '/', label: 'Home', icon: Home };


    const navGroups = [
        {
            title: "CREATE",
            items: [

                { path: '/generate', label: 'Studio', icon: Zap },
                { path: '/models', label: 'Models', icon: LayoutGrid },
                { path: '/mockup-studio', label: 'Bee Crate', icon: Package },
            ]
        },
        {
            title: "EXPLORE",
            items: [

                { path: '/generations', label: 'Feed', icon: Sparkles },
                { path: '/mockups', label: 'Mockups', icon: Images },
                { path: '/memes', label: 'Memes', icon: Smile },
            ]
        },
        {
            title: "SYSTEM",
            items: [
                { path: '/safety', label: 'Safety Center', icon: Shield },
                { path: '/pricing', label: 'Get Credits', icon: Hexagon },
            ]
        }
    ];

    const visibleGroups = navGroups.map(group => {
        const visibleItems = group.items.filter(item => {
            if (isAdmin) return true;
            // Public items for everyone

            if (item.path === '/mockups') return true;
            if (item.path === '/memes') return true;
            if (item.path === '/models') return true;
            if (item.path === '/generations') return true;
            if (item.path === '/generate') return true;


            // Logged in users
            if (currentUser) {
                if (item.path === '/generate') return true;
                if (item.path === '/mockup-studio') return true;
                if (item.path === '/mockup-studio') return true;
                if (item.path === '/pricing') return true;
                if (item.path === '/safety') return true;
            }

            return false;
        });
        return { ...group, items: visibleItems };
    }).filter(group => group.items.length > 0);

    return (
        <aside className="feed-sidebar-left">
            <Link to="/" className="sidebar-logo">
                <Hexagon size={24} fill="white" />
                <span className="logo-text">DreamBees</span>
            </Link>

            <nav className="sidebar-nav">
                {/* Primary Anchor */}
                <div className="nav-group primary-group">
                    <Link
                        to={homeLink.path}
                        className={`sidebar-link primary-link ${activeId === homeLink.path ? 'active' : ''}`}
                    >
                        <homeLink.icon size={20} />
                        <span className="link-label">{homeLink.label}</span>
                    </Link>

                </div>

                {/* Groups */}
                {visibleGroups.map((group, idx) => (
                    <CollapsibleGroup key={idx} title={group.title}>
                        {group.items.map(link => (
                            <Link
                                key={link.path}
                                to={link.path}
                                className={`sidebar-link ${activeId === link.path ? 'active' : ''}`}
                            >
                                <link.icon size={20} />
                                <span className="link-label">{link.label}</span>
                            </Link>
                        ))}
                    </CollapsibleGroup>
                ))}
            </nav>
            <style>{`
                .feed-sidebar-left {
                    /* Ensure scrollability */
                    overflow-y: auto;
                    max-height: 100vh;
                    scrollbar-width: thin;
                    scrollbar-color: rgba(255,255,255,0.1) transparent;
                    width: 240px; /* Fixed width for sidebar */
                    border-right: 1px solid rgba(255,255,255,0.1);
                    flex-shrink: 0;
                    padding-bottom: 20px;
                }
                .feed-sidebar-left::-webkit-scrollbar {
                    width: 4px;
                }
                .feed-sidebar-left::-webkit-scrollbar-thumb {
                    background: rgba(255,255,255,0.1);
                    border-radius: 4px;
                }

                .sidebar-logo {
                    display: flex;
                    align-items: center;
                    gap: 12px;
                    padding: 24px 24px;
                    text-decoration: none;
                    margin-bottom: 20px;
                }
                .logo-text {
                    font-size: 1.2rem;
                    font-weight: 800;
                    letter-spacing: -0.02em;
                    background: linear-gradient(135deg, #fff 0%, #a5b4fc 100%);
                    -webkit-background-clip: text;
                    -webkit-text-fill-color: transparent;
                }

                .sidebar-group-header {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    width: 100%;
                    padding: 16px 24px 8px 24px;
                    background: transparent;
                    border: none;
                    cursor: pointer;
                    color: rgba(255,255,255,0.4);
                    transition: color 0.2s;
                }
                .sidebar-group-header:hover {
                    color: rgba(255,255,255,0.7);
                }
                .group-title-text {
                    font-size: 0.7rem;
                    font-weight: 700;
                    letter-spacing: 0.05em;
                }
                .group-chevron {
                    opacity: 0.5;
                }

                .group-content {
                    overflow: hidden;
                    max-height: 0;
                    transition: max-height 0.3s cubic-bezier(0.2, 0.8, 0.2, 1);
                    opacity: 0;
                }
                .group-content.open {
                    max-height: 500px;
                    opacity: 1;
                    transition: max-height 0.5s cubic-bezier(0.2, 0.8, 0.2, 1), opacity 0.3s ease;
                }

                .sidebar-link {
                    padding: 10px 24px;
                    border-left: 3px solid transparent;
                    transition: all 0.2s ease;
                    display: flex;
                    align-items: center;
                    gap: 12px;
                    color: rgba(255,255,255,0.7);
                    text-decoration: none;
                    font-size: 0.95rem;
                }
                .sidebar-link:hover {
                    background: rgba(255,255,255,0.03);
                    color: #fff;
                }
                .sidebar-link.active {
                    background: rgba(139, 92, 246, 0.15); /* Brand tint */
                    border-left-color: #8b5cf6;
                    color: #fff;
                }
                .sidebar-link.active .lucide {
                    color: #8b5cf6;
                }

                /* Primary Link (Home) Special Styling */
                .primary-group {
                    margin-bottom: 8px;
                }
                .primary-link {
                    font-weight: 600;
                }
                .hype-badge-sidebar {
                    background: #a970ff;
                    color: white;
                    font-size: 0.6rem;
                    font-weight: 800;
                    padding: 1px 4px;
                    border-radius: 2px;
                    margin-left: 6px;
                }

                .hype-pulse {
                    box-shadow: 0 0 0 0 rgba(169, 112, 255, 0.7);
                    animation: pulse-hype 1.5s infinite;
                }

                @keyframes pulse-hype {
                    0% {
                        transform: scale(0.95);
                        box-shadow: 0 0 0 0 rgba(169, 112, 255, 0.7);
                    }
                    70% {
                        transform: scale(1);
                        box-shadow: 0 0 0 6px rgba(169, 112, 255, 0);
                    }
                    100% {
                        transform: scale(0.95);
                        box-shadow: 0 0 0 0 rgba(169, 112, 255, 0);
                    }
                }
            `}</style>
        </aside>
    );
};

export default React.memo(Sidebar);

