                                    onKeyDown={handleKeyDown}
                                    placeholder="Send a message"
                                    disabled={isLoading || isSending}
                                />
                                <button className="emote-btn" onClick={() => setShowEmotes(!showEmotes)}>
                                    😀
                                </button>
                            </div>
                            <div className="twitch-input-footer">
                                <div className="zaps-info" title={`Standard chat costs ${ZAP_COSTS.PERSONA_CHAT} Zaps`}>
                                    <Sparkles size={12} color="#8b5cf6" />
                                    <span>Chat: {ZAP_COSTS.PERSONA_CHAT} ZAPs</span>
                                </div>
                                <div style={{ display: 'flex', gap: '8px' }}>
                                    <button className="bits-btn zap-btn-pulse" onClick={() => handleGift(100)}>
                                        <Zap size={14} fill="#ffd700" /> ZAPs
                                    </button>
                                    <button
                                        onClick={handleSend}
                                        disabled={!inputValue.trim() || isLoading || isSending}
                                        className="twitch-chat-btn"
                                    >
                                        Chat
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <audio
                ref={audioVoiceRef}
                onEnded={handleAiAudioEnded}
                style={{ display: 'none' }}
            />
        </div>
    );
};

export default PersonaChat;

import { initializeApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import { getFirestore, initializeFirestore, memoryLocalCache } from "firebase/firestore";
import { getStorage } from "firebase/storage";
import { getFunctions } from "firebase/functions";


const firebaseConfig = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
  authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
  storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: import.meta.env.VITE_FIREBASE_APP_ID
};

let app;
let auth;
let dbInstance;
let storage;
let functions;

try {
  if (!firebaseConfig.apiKey) {
    throw new Error("Missing Firebase API Key. Check .env configuration.");
  }

  app = initializeApp(firebaseConfig);
  auth = getAuth(app);
  storage = getStorage(app);
  functions = getFunctions(app, 'us-central1');

  try {
    // Use memory cache explicitly to prevent "Unexpected state" internal assertion errors
    dbInstance = initializeFirestore(app, {
      localCache: memoryLocalCache(),
    });
    console.log("[Firebase] Firestore initialized (Memory Cache Mode).");
  } catch (firestoreError) {
    console.warn("[Firebase] Primary Firestore initialization failed. Attempting fallback...", firestoreError);
    try {
      dbInstance = getFirestore(app);
      console.log("[Firebase] Firestore initialized with default settings (Fallback).");
    } catch (fallbackError) {
      console.error("[Firebase] CRITICAL: Firestore initialization completely failed.", fallbackError);
      // dbInstance remains undefined
    }
  }

} catch (error) {
  console.error("[Firebase] CRITICAL: Firebase app initialization failed.", error);
  // Create mock objects or leave as undefined to allow app to render error boundary
}

export { auth, storage, functions };
export const db = dbInstance;

import { useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApi } from '../../hooks/useApi';
import { doc, onSnapshot } from 'firebase/firestore';
import { db } from '../../firebase';
import toast from 'react-hot-toast';
import { trackEvent, trackCreativeTelemetry, trackFriction } from '../../utils/analytics';
import { calculateZapCost } from '../../constants/zapCosts';

// Reliability Constants
const DEBOUNCE_MS = 2000;        // Minimum time between generation requests
const SLOW_THRESHOLD_MS = 120000; // 2 min - show "taking longer" message

export function useGenerationLogic({
    prompt,
    selectedModel,
    generationMode,
    negPrompt,
    aspectRatio, steps, cfg, seed, useTurbo,
    zaps, reels: _reels, subscriptionStatus,
    setGenerating, setGeneratedImage, setCurrentJobType, setCurrentJobId, setActiveJob,
    deductZapsOptimistically,
    rollbackZaps,
    referenceImage, // Added to support img2img
    currentUser // Added to support auth check
}) {
    const navigate = useNavigate();
    // Track timing
    const startTimeRef = useRef(null);
    // Track the current job listener
    const unsubscribeRef = useRef(null);
    const currentJobIdRef = useRef(null);

    // Reliability: Debounce guard
    const lastRequestTimeRef = useRef(null);

    // Cleanup listener on unmount
    useEffect(() => {
        return () => {
            if (unsubscribeRef.current) {
                unsubscribeRef.current();
            }
        };
    }, []);

    const { call: apiCall } = useApi();

    // Listen to job status changes
    const listenToJob = (requestId, isRestored = false) => {
        // Cleanup any existing listener
        if (unsubscribeRef.current) {
            unsubscribeRef.current();
        }

        currentJobIdRef.current = requestId;
        let lastKnownStatus = 'queued';
        let fallbackTimer = null;

        const cleanup = () => {
            if (unsubscribeRef.current) {
                unsubscribeRef.current();
                unsubscribeRef.current = null;
            }
            if (fallbackTimer) {
                clearInterval(fallbackTimer);
                fallbackTimer = null;
            }
            localStorage.removeItem('activeGenerationJob');
        };

        // Advanced Stability: Backup Polling Fallback
        // If onSnapshot stalls or Firestore stream breaks, this ensures we eventually get the result.
        const startFallback = () => {
            if (fallbackTimer) return;
            console.log(`[useGenerationLogic] Initializing backup polling for ${requestId}`);
            fallbackTimer = setInterval(async () => {
                try {
                    const { getDoc, doc } = await import('firebase/firestore');
                    const snap = await getDoc(doc(db, 'generation_queue', requestId));
                    if (snap.exists()) {
                        const data = snap.data();
                        handleStatusUpdate(data);
                    }
                } catch (err) {
                    console.error("[useGenerationLogic] Fallback poll failed:", err);
                }
            }, 10000); // Poll every 10s as a safety net
        };

        const handleStatusUpdate = (data) => {
            if (!data) return;

            if (data.status === 'completed' && data.imageUrl) {
                setGeneratedImage(data.imageUrl);
                setGenerating(false);
                if (setActiveJob) {
                    setActiveJob({ id: requestId, ...data });
                }
                toast.success('Image generated successfully! 🎨', { id: 'gen-image' });
                cleanup();

                const promptLength = data.prompt?.length || 0;
                const promptBucket = promptLength <= 50 ? 'short' : (promptLength <= 150 ? 'medium' : 'long');

                trackEvent('generate_image_success', {
                    model_id: data.modelId,
                    job_id: requestId,
                    duration_ms: startTimeRef.current ? Date.now() - startTimeRef.current : undefined,
                    aspect_ratio: data.aspectRatio || aspectRatio,
                    prompt_length_bucket: promptBucket
                });

                trackCreativeTelemetry('generation_success', {
                    model_id: data.modelId,
                    aspect_ratio: data.aspectRatio || aspectRatio,
                    prompt_length_bucket: promptBucket
                });
            } else if (data.status === 'failed') {
                setGenerating(false);
                toast.error(`Generation failed: ${data.error || 'Unknown error'}`, { id: 'gen-image' });

                trackEvent('generate_image_failure', {
                    model_id: data.modelId || selectedModel?.id,
                    error: data.error || 'Server Side Failure'
                });
                trackFriction('generation_failure', 'Generation_Listener', data.error || 'Server Side Failure');
                cleanup();
            } else if (data.status === 'processing' && lastKnownStatus !== 'processing') {
                lastKnownStatus = 'processing';
                toast.loading('Processing your image...', { id: 'gen-image' });
            }

            // Slow Detection: Notify user if taking longer than usual
            if (data.status === 'processing' && startTimeRef.current) {
                const elapsedTime = Date.now() - startTimeRef.current;
                if (elapsedTime > SLOW_THRESHOLD_MS) {
                    toast.loading('This is taking longer than usual...', { id: 'gen-image' });
                }
            }
        };

        // Start fallback after a short delay to see if onSnapshot works
        const gracePeriod = isRestored ? 2000 : 25000;
        setTimeout(startFallback, gracePeriod);

        const unsubscribe = onSnapshot(
            doc(db, 'generation_queue', requestId),
            (docSnap) => {
                if (!docSnap.exists()) return;
                handleStatusUpdate(docSnap.data());
            },
            (error) => {
                console.error('[useGenerationLogic] Listener error:', error);
                startFallback(); // Immediate fallback trigger on error
            }
        );

        unsubscribeRef.current = unsubscribe;
    };

    const handleGenerate = async (promptOverride = null) => {
        let requestId = 'legacy';
        try {
            // Debounce Guard: Prevent rapid duplicate submissions
            const now = Date.now();
            if (lastRequestTimeRef.current && (now - lastRequestTimeRef.current < DEBOUNCE_MS)) {
                toast('Too fast! Please wait a moment.', { icon: '⏳', id: 'debounce' });
                return;
            }
            lastRequestTimeRef.current = now;

            if (!currentUser) {
                toast.error("Please log in to generate images");
                navigate('/auth');
                return;
            }

            const effectivePrompt = (typeof promptOverride === 'string' ? promptOverride : prompt);

            if (!effectivePrompt || !selectedModel) {
                return;
            }

            // Cost Checks
            if (generationMode === 'video') {
                console.warn('[handleGenerate] ABORT: Video mode - should use video generation hook');
                return;
            }

            const cost = calculateZapCost('IMAGE_GENERATION', {
                subscriptionStatus,
                modelId: selectedModel.id,
                useTurbo
            });

            if (zaps < cost && cost > 0) {
                toast.error(`Insufficient Zaps ⚡ (Need ${cost}, have ${zaps.toFixed(1)})`);
                trackFriction('insufficient_credits', 'Generation_Start', `Need ${cost}, have ${zaps}`);
                return;
            }

            // Generate unique requestId for deduplication and optimistic tracking
            requestId = `gen_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;

            // Optimistic Deduction
            if (cost > 0 && deductZapsOptimistically) {
                deductZapsOptimistically(cost, requestId);
            }

            setGenerating(true);
            setGeneratedImage(null);
            setCurrentJobType(generationMode);
            startTimeRef.current = Date.now();

            const finalPrompt = effectivePrompt;
            const finalNegativePrompt = negPrompt;

            const progressUpdates = [
                { delay: 500, message: `🚀 Queueing request...` },
                { delay: 1500, message: `🎨 Allocating GPU resources...` },
                { delay: 3500, message: `🖌️ Painting your vision...` },
                { delay: 6000, message: `✨ Refining details...` }
            ];

            const progressTimers = progressUpdates.map(({ delay, message }) =>
                setTimeout(() => toast.loading(message, { id: 'gen-image' }), delay)
            );

            const clearProgressTimers = () => progressTimers.forEach(timer => clearTimeout(timer));
            toast.loading("Starting generation...", { id: 'gen-image' });

            const { data } = await apiCall('api', {
                action: 'createGenerationRequest',
                prompt: finalPrompt,
                negative_prompt: finalNegativePrompt,
                modelId: selectedModel.id,
                aspectRatio: aspectRatio,
                steps: steps,
                cfg: cfg,
                seed: seed,
                useTurbo,
                requestId, // Pass the client-generated ID
                image: referenceImage, // Pass the reference image for img2img
                isPublic: true // Force public visibility for feed discovery
            }, {
                timeout: 540000,
                toastErrors: false // We handle errors manually below
            });

            trackEvent('generate_image_start', {
                model_id: selectedModel.id,
                generation_mode: generationMode,
                aspect_ratio: aspectRatio
            });

            const promptLength = finalPrompt?.length || 0;
            const promptBucket = promptLength <= 50 ? 'short' : (promptLength <= 150 ? 'medium' : 'long');

            trackCreativeTelemetry('generation_start', {
                model_id: selectedModel.id,
                aspect_ratio: aspectRatio,
                prompt_length_bucket: promptBucket
            });

            const { requestId: serverRequestId } = data;
            const finalRequestId = serverRequestId || requestId;

            setCurrentJobId(finalRequestId);
            clearProgressTimers();
            toast.loading("Generation in progress...", { id: 'gen-image' });

            // Persist
            localStorage.setItem('activeGenerationJob', JSON.stringify({
                requestId: finalRequestId,
                jobType: generationMode
            }));

            // Start listening for job completion
            listenToJob(finalRequestId);

        } catch (error) {
            console.error("[handleGenerate] CAUGHT ERROR:", error);
            const cost = calculateZapCost('IMAGE_GENERATION', {
                subscriptionStatus,
                modelId: selectedModel.id,
                useTurbo
            });
            if (cost > 0 && rollbackZaps) {
                rollbackZaps(cost, requestId);
            }
            setGenerating(false);
            const errorMessage = error.message || "Failed to create generation request";
            toast.error(errorMessage, { id: 'gen-image' });
            localStorage.removeItem('activeGenerationJob');
        }
    };

    // Restore on mount
    useEffect(() => {
        const saved = localStorage.getItem('activeGenerationJob');
        if (saved) {
            try {
                const { requestId, jobType } = JSON.parse(saved);
                if (requestId) {
                    console.log("Restoring active generation job:", requestId);
                    // We need these setters to handle the restored state
                    if (setGenerating) setGenerating(true);
                    if (setCurrentJobId) setCurrentJobId(requestId);
                    if (setCurrentJobType && jobType) setCurrentJobType(jobType);

                    listenToJob(requestId);
                }
            } catch (e) {
                console.error("Failed to restore job:", e);
                localStorage.removeItem('activeGenerationJob');
            }
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    const cancelGeneration = () => {
        if (unsubscribeRef.current) {
            unsubscribeRef.current();
            unsubscribeRef.current = null;
        }
        setGenerating(false);
        localStorage.removeItem('activeGenerationJob');
        toast('Generation stopped', { icon: '🛑', id: 'gen-image' });
    };

    return { handleGenerate, cancelGeneration };
}

import { useState, useRef, useEffect } from 'react';
import { httpsCallable } from 'firebase/functions';
import { doc, onSnapshot } from 'firebase/firestore';
import { db, functions } from '../../firebase';
import toast from 'react-hot-toast';
import { STYLE_REGISTRY } from '../../data/styles';
import { compressImage } from '../../utils';

export function useMagicEnhance({
    prompt, setPrompt,
    referenceImage, setReferenceImage,
    activeStyleId,
    generatedImage, setGeneratedImage,
    activeJob, setActiveJob,
    styleIntensity,
    handleGenerate, // Callback to trigger standard generation if needed
    deductZapsOptimistically,
    rollbackZaps
}) {
    const [isEnhancing, setIsEnhancing] = useState(false);
    const [enhanceStatus, setEnhanceStatus] = useState(''); // 'transforming', 'enhancing', 'uploading', etc.
    const listenerRef = useRef(null);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            if (listenerRef.current) {
                listenerRef.current();
            }
        };
    }, []);

    const handleMagicEnhance = async () => {
        if (isEnhancing) return;
        let requestId = 'legacy';

        // Capture current values
        let currentReferenceImage = referenceImage;
        const currentPrompt = prompt;

        // Fallback Logic
        if (activeStyleId) {
            if (!currentReferenceImage && activeJob && (activeJob.imageUrl || activeJob.thumbnailUrl)) {
                console.log("[handleMagicEnhance] ReferenceImage is null, using activeJob image as fallback");
                currentReferenceImage = activeJob.imageUrl || activeJob.thumbnailUrl;
                setReferenceImage(currentReferenceImage);
            }
            if (!currentReferenceImage && generatedImage) {
                console.log("[handleMagicEnhance] ReferenceImage is null, using generatedImage as fallback");
                currentReferenceImage = generatedImage;
                setReferenceImage(currentReferenceImage);
            }
        }

        if (!currentPrompt && !currentReferenceImage) {
            console.log("[handleMagicEnhance] Early return: no prompt and no referenceImage");
            return;
        }

        setIsEnhancing(true);

        const isReferenceImageValid = (img) => img && typeof img === 'string' && img.trim().length > 0;

        try {
            const api = httpsCallable(functions, 'api', { timeout: 540000 });
            const hasValidReferenceImage = isReferenceImageValid(currentReferenceImage);
            const hasValidPrompt = currentPrompt && typeof currentPrompt === 'string' && currentPrompt.trim().length > 0;

            // 1. Image Transformation (Style Transfer)
            if (hasValidReferenceImage && activeStyleId) {
                const styleObj = STYLE_REGISTRY.find(s => s.id === activeStyleId);
                if (!styleObj || !styleObj.instruction) {
                    toast.error("Selected style is missing instructions", { id: 'style-magic' });
                    setIsEnhancing(false);
                    return;
                }

                if (currentReferenceImage && !generatedImage) {
                    setGeneratedImage(currentReferenceImage); // Show original temporarily
                }

                setEnhanceStatus('Transforming image...');
                toast.loading(`✨ Starting ${styleObj.label} transformation...`, { id: 'style-magic' });

                const cost = 0.5; // IMAGE_TRANSFORM
                requestId = `tr_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;
                if (deductZapsOptimistically) deductZapsOptimistically(cost, requestId);

                try {
                    let processedImage = currentReferenceImage;
                    if (processedImage && processedImage.startsWith('data:')) {
                        setEnhanceStatus('Compressing...');
                        processedImage = await compressImage(processedImage, 1024, 0.7);
                    }

                    const progressUpdates = [
                        { delay: 300, message: `📤 Uploading image to AI...`, status: 'Uploading...' },
                        { delay: 800, message: `🎨 AI is transforming with ${styleObj.label} style...`, status: 'Stylizing...' },
                        { delay: 2000, message: `⚙️ Processing transformation...`, status: 'Processing...' },
                        { delay: 4000, message: `✨ Finalizing your transformed image...`, status: 'Finalizing...' }
                    ];

                    const progressTimers = progressUpdates.map(({ delay, message, status }) =>
                        setTimeout(() => {
                            toast.loading(message, { id: 'style-magic' });
                            setEnhanceStatus(status);
                        }, delay)
                    );

                    const clearProgressTimers = () => progressTimers.forEach(timer => clearTimeout(timer));

                    const transformResult = await api({
                        action: 'transformImage',
                        imageUrl: processedImage,
                        styleName: styleObj.label,
                        intensity: styleIntensity,
                        instructions: styleObj.instruction,
                        requestId
                    });

                    clearProgressTimers();

                    if (transformResult?.data?.imageUrl) {
                        const imageToShow = transformResult.data.thumbnailUrl || transformResult.data.imageUrl;

                        // Preload
                        const img = new Image();
                        img.src = transformResult.data.imageUrl;

                        toast.loading(`🎉 Loading your transformed image...`, { id: 'style-magic' });
                        setGeneratedImage(imageToShow);

                        img.onload = () => setGeneratedImage(transformResult.data.imageUrl);

                        if (transformResult.data.imageId) {
                            setActiveJob({
                                id: transformResult.data.imageId,
                                imageUrl: transformResult.data.imageUrl,
                                thumbnailUrl: transformResult.data.thumbnailUrl,
                                prompt: `Vision Transformation: ${styleObj.label}`
                            });
                        }

                        setReferenceImage(null);
                        setTimeout(() => {
                            toast.success(`✨ ${styleObj.label} transformation complete!`, { id: 'style-magic', duration: 3000, icon: '🎨' });
                        }, 200);
                        setIsEnhancing(false);
                        setEnhanceStatus('');
                        return;
                    } else {
                        clearProgressTimers();
                        throw new Error("Transformation failed to return an image");
                    }
                } catch (error) {
                    const cost = 0.5; // IMAGE_TRANSFORM
                    if (rollbackZaps) rollbackZaps(cost, requestId);

                    console.error("[handleMagicEnhance] transformImage error:", error);
                    let errorMessage = error.message || "Failed to transform image";
                    if (errorMessage.includes('INVALID_ARGUMENT') || errorMessage.includes('too large')) {
                        errorMessage = "Image too large. Compression failed.";
                    }
                    toast.error(`Transformation failed: ${errorMessage}`, { id: 'style-magic', duration: 4000 });
                    setIsEnhancing(false);
                    setEnhanceStatus('');
                    return;
                }
            }

            // 2. Prompt Transformation
            if (hasValidPrompt) {
                if (activeStyleId) {
                    const styleObj = STYLE_REGISTRY.find(s => s.id === activeStyleId);
                    if (styleObj && styleObj.instruction) {
                        toast.loading(`✨ Transforming prompt with ${styleObj.label}...`, { id: 'style-magic' });

                        try {
                            const transformResult = await api({
                                action: 'transformPrompt',
                                prompt: currentPrompt,
                                styleName: styleObj.label,
                                intensity: styleIntensity,
                                instructions: styleObj.instruction
                            });

                            const newPrompt = transformResult?.data?.prompt;
                            if (!newPrompt) {
                                toast.error("Empty prompt returned", { id: 'style-magic' });
                                setIsEnhancing(false);
                                setEnhanceStatus('');
                                return;
                            }

                            toast.loading(`✨ Applying ${styleObj.label} style...`, { id: 'style-magic' });
                            setPrompt(newPrompt);

                            setTimeout(() => {
                                toast.success(`✨ Prompt transformed!`, { id: 'style-magic', duration: 2000, icon: '✨' });
                            }, 100);

                            setIsEnhancing(false);
                            setEnhanceStatus('');

                            // Auto-Trigger Generation
                            setTimeout(() => {
                                handleGenerate(newPrompt);
                            }, 400);
                            return;

                        } catch (error) {
                            console.error("Transform prompt error", error);
                            toast.error("Failed to transform prompt", { id: 'style-magic' });
                            setIsEnhancing(false);
                            setEnhanceStatus('');
                            return;
                        }
                    }
                }

                // 3. Standard Magic Enhance (No Style)
                try {
                    const cost = 1.0; // IMAGE_ENHANCE
                    requestId = `en_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;
                    if (deductZapsOptimistically) deductZapsOptimistically(cost, requestId);

                    const result = await api({ action: 'createEnhanceRequest', prompt: currentPrompt, requestId });
                    const finalRequestId = result.data.requestId || requestId;

                    // Set safety timeout (60s)
                    const timeoutId = setTimeout(() => {
                        toast.error("Enhance request timed out", { id: 'style-magic' });
                        setIsEnhancing(false);
                        setEnhanceStatus('');
                    }, 60000);

                    // Advanced Stability: Backup Polling Fallback
                    let fallbackTimer = null;
                    const startFallback = () => {
                        if (fallbackTimer) return;
                        fallbackTimer = setInterval(async () => {
                            try {
                                const { getDoc, doc } = await import('firebase/firestore');
                                const snap = await getDoc(doc(db, 'enhance_queue', finalRequestId));
                                if (snap.exists()) {
                                    const data = snap.data();
                                    if (data.status === 'completed' || data.status === 'failed') {
                                        handleStatus(data);
                                    }
                                }
                            } catch (e) { console.error("Enhance fallback fail", e); }
                        }, 10000);
                    };

                    const handleStatus = (data) => {
                        if (data.status === 'completed') {
                            clearTimeout(timeoutId);
                            if (fallbackTimer) clearInterval(fallbackTimer);
                            setPrompt(data.prompt);
                            toast.success("Magic enhanced!", { id: 'style-magic' });
                            setIsEnhancing(false);
                            setEnhanceStatus('');
                            if (listenerRef.current) {
                                listenerRef.current();
                                listenerRef.current = null;
                            }
                        } else if (data.status === 'failed') {
                            clearTimeout(timeoutId);
                            if (fallbackTimer) clearInterval(fallbackTimer);
                            toast.error("Failed: " + (data.error || "Unknown"), { id: 'style-magic' });
                            setIsEnhancing(false);
                            setEnhanceStatus('');
                            if (listenerRef.current) {
                                listenerRef.current();
                                listenerRef.current = null;
                            }
                        }
                    };

                    setTimeout(startFallback, 25000);

                    const unsubscribe = onSnapshot(doc(db, 'enhance_queue', finalRequestId), (snapshot) => {
                        if (!snapshot.exists()) return;
                        handleStatus(snapshot.data());
                    }, (err) => {
                        console.error("Enhance listener err", err);
                        startFallback();
                    });
                    listenerRef.current = unsubscribe;
                } catch (error) {
                    const cost = 1.0; // IMAGE_ENHANCE
                    if (rollbackZaps) rollbackZaps(cost, requestId);

                    console.error("Enhance request error", error);
                    toast.error("Failed to enhance prompt", { id: 'style-magic' });
                    setIsEnhancing(false);
                }
                return;
            }

            toast.error("Please provide an image or prompt", { id: 'style-magic' });
            setIsEnhancing(false);

        } catch (error) {
            console.error("Unexpected error", error);
            toast.error("Request failed", { id: 'style-magic' });
            setIsEnhancing(false);
            setEnhanceStatus('');
        }
    };

    return { isEnhancing, enhanceStatus, handleMagicEnhance };

}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
// import { httpsCallable } from 'firebase/functions'; // Removed
import { db } from '../../firebase';
import { useApi } from '../../hooks/useApi';
import { onSnapshot, query, collection, where, orderBy, limit } from 'firebase/firestore';
import toast from 'react-hot-toast';
import { compressImage } from '../../utils';

export function useVideoGeneration({
    currentUser,
    generating, setGenerating,
    setGeneratedImage,
    setReferenceImage,
    setPrompt,
    setCurrentJobType,
    setCurrentJobId,
    setAnalyzingImageId,
    videoDuration,
    videoResolution,
    aspectRatio,
    reels: _reels,
    deductReelsOptimistically,
    rollbackReels
}) {
    const [recentImages, setRecentImages] = useState([]);

    // Fetch Recent Images
    useEffect(() => {
        if (currentUser) {
            const q = query(
                collection(db, 'generation_queue'),
                where('userId', '==', currentUser.uid),
                where('status', '==', 'completed'),
                orderBy('createdAt', 'desc'),
                limit(20)
            );
            const unsubscribe = onSnapshot(q, (snapshot) => {
                setRecentImages(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
            });
            return () => unsubscribe();
        }
    }, [currentUser]);

    const { call: apiCall } = useApi();
    const navigate = useNavigate();

    const triggerVideoAnimation = async (imageUrl, imageId = null, imgAspectRatio = null) => {
        if (generating) return;

        if (!currentUser) {
            toast.error("Please log in to animate images");
            navigate('/auth');
            return;
        }

        if (imageId) setAnalyzingImageId(imageId);
        setGenerating(true);
        setGeneratedImage(null);
        setCurrentJobType('video');
        setReferenceImage(imageUrl);
        setPrompt("Analyzing image...");

        const progressUpdates = [
            { delay: 500, message: `🎬 Preparing video studio...` },
            { delay: 1500, message: `📤 Uploading image for analysis...` },
            { delay: 3500, message: `🤖 Analyzing scene composition...` },
            { delay: 6000, message: `🎥 Configuring camera motion...` },
            { delay: 9000, message: `✨ Queuing generation job...` }
        ];

        const progressTimers = progressUpdates.map(({ delay, message }) =>
            setTimeout(() => toast.loading(message, { id: 'video-animate' }), delay)
        );

        const clearProgressTimers = () => progressTimers.forEach(timer => clearTimeout(timer));

        toast.loading("Starting video animation...", { id: 'video-animate' });

        let requestId = 'legacy';
        try {
            let processedImage = imageUrl;

            if (imageUrl && imageUrl.startsWith('data:')) {
                console.log(`[Video] Compressing input image...`);
                processedImage = await compressImage(imageUrl, 1024, 0.7);
            }

            // const api = httpsCallable(functions, 'api', { timeout: 540000 });
            // Replaced with useApi call
            requestId = `vid_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;
            const cost = 1; // Video generation costs 1 Reel
            if (deductReelsOptimistically) deductReelsOptimistically(cost, requestId);

            const { data } = await apiCall('api', {
                action: 'createVideoGenerationRequest',
                autoPrompt: true,
                image: processedImage,
                duration: videoDuration,
                resolution: videoResolution,
                aspectRatio: imgAspectRatio || aspectRatio,
                requestId
            }, {
                timeout: 540000,
                toastErrors: false // We handle specific errors below
            });

            setCurrentJobId(data.requestId);
            clearProgressTimers();
            toast.success("Video job finished setup!", { id: 'video-animate' });

        } catch (error) {
            clearProgressTimers();
            console.error("Video generation error", error);

            const cost = 1;
            if (rollbackReels) rollbackReels(cost, requestId);

            let errorMessage = "Failed to animate image.";
            if (error.message?.includes('concurrency')) errorMessage = "Video generation already in progress.";
            else if (error.code === 'resource-exhausted') errorMessage = "Insufficient Reels balance.";
            else if (error.message?.includes('INVALID_ARGUMENT')) errorMessage = "Image too large or invalid.";
            else if (error.message) errorMessage = error.message;

            toast.error(errorMessage, { id: 'video-animate' });
            setGenerating(false);
            setPrompt("");
            setReferenceImage(null);
        } finally {
            setAnalyzingImageId(null);
        }
    };

    const handleVideoAutoAnimate = (image) => triggerVideoAnimation(image.imageUrl, image.id, image.aspectRatio);

    return {
        recentImages,
        triggerVideoAnimation,
        handleVideoAutoAnimate
    };
}

