                    letter-spacing: 0.05em;
                    cursor: pointer;
                    transition: all 0.2s;
                    border-radius: 100px;
                }
                .tab-btn:hover {
                    color: white;
                    background: rgba(255,255,255,0.05);
                }
                .tab-btn.active {
                    color: black;
                    background: white;
                    border-color: white;
                }

                /* Global Mobile Styles */
                @media (max-width: 600px) {
                    .instagram-feed {
                        gap: 10px !important;
                        padding-top: 20px;
                    }
                    .feed-post {
                        border-radius: 0 !important;
                        border-left: none !important;
                        border-right: none !important;
                        background: transparent !important;
                    }
                    .segmented-control {
