import React, { useEffect, useState, useCallback, useRef, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Share2, Sparkles, Heart, RefreshCw, MoreHorizontal, Shuffle, Flag } from 'lucide-react';

import { motion, AnimatePresence } from 'framer-motion';

import { useModel } from '../contexts/ModelContext';
import { useUserInteractions } from '../contexts/UserInteractionsContext';
import { getOptimizedImageUrl } from '../utils';
import {
    getDiversifiedRecommendations,
    getRecommendationsWithHistory,
    getExplorationRecommendations,
    getBalancedRecommendations
} from '../utils/relevance';
import { doc, getDoc } from 'firebase/firestore';
import { db } from '../firebase';
import { slugify } from '../utils/urlHelpers';
import toast from 'react-hot-toast';
import SEO from '../components/SEO';
import './ShowcaseDetail.css';

const SHOWCASE_PAGE_SIZE = 12;
const CACHE_TARGET = 150;
const HISTORY_CAP = 100; // Max history items to track

const ShowcaseDetail = React.memo(function ShowcaseDetail() {
    const { id: rawId } = useParams();
    // Support robust ID extraction: 
    // 1. Double hyphen separator (new standard) 
    // 2. Single hyphen separator (legacy)
    // 3. Fallback to rawId
    const id = useMemo(() => {
        if (!rawId) return null;
        if (rawId.includes('--')) return rawId.split('--').pop();
        if (rawId.includes('-')) return rawId.split('-').pop();
        return rawId;
    }, [rawId]);
    const navigate = useNavigate();

    // Core Data
    const { globalShowcaseCache, availableModels, getGlobalShowcaseImages, hasMoreGlobal } = useModel();
    const { isLiked, toggleLike, hidePost, isHidden } = useUserInteractions();

    // State
    const [images, setImages] = useState([]);
    const [loading, setLoading] = useState(true);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [shuffleToast, setShuffleToast] = useState(null);
    const isFetchingMoreRef = useRef(false);

    // Filter hidden images from global cache initially but keep local management
    const visibleGlobalCache = useMemo(() => globalShowcaseCache.filter(img => !isHidden(img.id)), [globalShowcaseCache, isHidden]);

    // Track seen images to avoid repetition
    const seenIdsRef = useRef(new Set());

    // Refs for Scroll & Observation
    const containerRef = useRef(null);
    const observerRef = useRef(null);
    const isInitialMount = useRef(true);
    const currentImageRef = useRef(null);


    // Helper to show toast notifications
    const showToast = useCallback((message, icon = 'shuffle') => {
        setShuffleToast({ message, icon });
        setTimeout(() => setShuffleToast(null), 2500);
    }, []);

    // 1. Initialize Feed (Load initial image + recommendations)
    useEffect(() => {
        const initFeed = async () => {
            if (!isInitialMount.current && images.length > 0) return;

            setLoading(true);

            // Ensure we have some global cache
            if (visibleGlobalCache.length < CACHE_TARGET && hasMoreGlobal && !isFetchingMoreRef.current) {
                isFetchingMoreRef.current = true;
                getGlobalShowcaseImages(true, 'showcasedetail_init').finally(() => {
                    isFetchingMoreRef.current = false;
                });
            }

            let startImage = visibleGlobalCache.find(img => img.id === id || img.id === rawId);

            // If not in cache, fetch directly (Try both extracted id and full rawId)
            if (!startImage) {
                const tryIds = [rawId];
                if (id && id !== rawId) tryIds.push(id);

                for (const targetId of tryIds) {
                    try {
                        // 1. Try official showcase
                        const showcaseRef = doc(db, 'model_showcase_images', targetId);
                        const showcaseSnap = await getDoc(showcaseRef);

                        if (showcaseSnap.exists()) {
                            startImage = { id: showcaseSnap.id, ...showcaseSnap.data() };
                            break;
                        } else {
                            // 2. Try user generations (if public)
                            const generationRef = doc(db, 'generations', targetId);
                            const generationSnap = await getDoc(generationRef);

                            if (generationSnap.exists()) {
                                const data = generationSnap.data();
                                if (data.isPublic) {
                                    startImage = { id: generationSnap.id, ...data };
                                    break;
                                }
                            }
                        }
                    } catch (err) {
                        // Only log non-permission errors (permission errors are expected for private/non-existent images)
                        if (err.code !== 'permission-denied') {
                            console.error(`Error fetching image for ID ${targetId}:`, err);
                        }
                    }
                }
            }

            if (startImage) {
                // Track the start image as seen
                seenIdsRef.current.add(startImage.id);

                // Get highly diversified recommendations using the enhanced algorithm
                const recs = getDiversifiedRecommendations(startImage, visibleGlobalCache, SHOWCASE_PAGE_SIZE);

                // Track all initial recs as seen
                recs.forEach(r => seenIdsRef.current.add(r.id));

                // Filter out duplicates just in case
                const uniqueRecs = recs.filter(r => r.id !== startImage.id);
                setImages([startImage, ...uniqueRecs]);

                // Store reference to current image for recommendations
                currentImageRef.current = startImage;
            }

            setLoading(false);
            isInitialMount.current = false;
        };

        initFeed();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [id, globalShowcaseCache, hasMoreGlobal, getGlobalShowcaseImages, visibleGlobalCache.length, rawId]);


    // 3. Load More Strategy - Now with history awareness
    const loadMoreImages = useCallback(() => {
        if (!currentImageRef.current) return;

        // Get seen IDs array (capped to avoid memory issues)
        const seenArray = Array.from(seenIdsRef.current).slice(-HISTORY_CAP);

        // Use history-aware recommendations for truly fresh content
        const freshRecs = getRecommendationsWithHistory(
            currentImageRef.current,
            visibleGlobalCache,
            seenArray,
            SHOWCASE_PAGE_SIZE
        );

        if (freshRecs.length === 0 && hasMoreGlobal) {
            console.log("[Feed] Cache exhausted, fetching more...");
            if (!isFetchingMoreRef.current) {
                isFetchingMoreRef.current = true;
                getGlobalShowcaseImages(true, 'feed_scroll_replenish').finally(() => {
                    isFetchingMoreRef.current = false;
                });
            }
            return;
        }

        if (freshRecs.length > 0) {
            // Mark new batch as seen
            freshRecs.forEach(r => seenIdsRef.current.add(r.id));
            setImages(prev => [...prev, ...freshRecs]);
        }
    }, [visibleGlobalCache, hasMoreGlobal, getGlobalShowcaseImages]);


    // 2. Intersection Observer for Current Index & URL Update
    useEffect(() => {
        const options = {
            root: containerRef.current,
            threshold: 0.6, // Item is "active" when 60% visible
        };

        observerRef.current = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    const index = Number(entry.target.dataset.index);
                    setCurrentIndex(index);

                    // Update URL silently (replace) without full reload
                    const img = images[index];
                    if (img && img.id !== id) {
                        const slug = slugify(img.prompt?.slice(0, 40) || 'artwork');
                        navigate(`/discovery/${slug}--${img.id}`, { replace: true });

                        // Mark as seen
                        seenIdsRef.current.add(img.id);

                        // Update current reference for future recs
                        currentImageRef.current = img;
                    }

                    // Load more trigger - only when near end
                    if (index >= images.length - 4 && hasMoreGlobal) {
                        loadMoreImages();
                    }
                }
            });
        }, options);

        // Subscribing to elements
        const elements = document.querySelectorAll('.feed-item');
        elements.forEach(el => observerRef.current.observe(el));

        return () => {
            if (observerRef.current) observerRef.current.disconnect();
        };
    }, [images, id, navigate, hasMoreGlobal, loadMoreImages]);




    // 4. Shuffle Action - Complete feed refresh with exploration mode
    const handleShuffle = useCallback(() => {
        if (!currentImageRef.current || globalShowcaseCache.length === 0) return;

        // Get current seen history
        const seenArray = Array.from(seenIdsRef.current);

        // First, try to get fresh exploration recommendations
        const explorationPicks = getExplorationRecommendations(
            visibleGlobalCache,
            SHOWCASE_PAGE_SIZE,
            seenArray
        );

        if (explorationPicks.length < 3) {
            // Not enough fresh content
            showToast("🔄 Loading fresh content...", "refresh");
            if (hasMoreGlobal && !isFetchingMoreRef.current) {
                isFetchingMoreRef.current = true;
                getGlobalShowcaseImages(true, 'shuffle_fetch').finally(() => {
                    isFetchingMoreRef.current = false;
                });
            }
            return;
        }

        // Track new items
        explorationPicks.forEach(r => seenIdsRef.current.add(r.id));

        // Keep current image, replace everything after with exploration
        const currentImg = images[currentIndex];
        setImages([currentImg, ...explorationPicks]);
        setCurrentIndex(0);

        // Scroll to top
        if (containerRef.current) {
            containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
        }

        showToast(`🎲 ${explorationPicks.length} fresh picks!`, "shuffle");
    }, [currentIndex, images, visibleGlobalCache, globalShowcaseCache.length, hasMoreGlobal, getGlobalShowcaseImages, showToast]);


    // 5. Balanced Mode - More similar but still diverse
    const handleMoreLikeThis = useCallback(() => {
        if (!currentImageRef.current || globalShowcaseCache.length === 0) return;

        const unseen = visibleGlobalCache.filter(c => !seenIdsRef.current.has(c.id));

        // Use balanced recommendations with stricter similarity
        const similarPicks = getBalancedRecommendations(
            currentImageRef.current,
            unseen,
            {
                limit: SHOWCASE_PAGE_SIZE,
                maxSameModel: 3,  // Allow more from same model
                maxSamePrimaryStyle: 5,  // Allow more similar styles
                maxSameMood: 4,
            }
        );

        if (similarPicks.length < 3) {
            showToast("🔍 Finding more similar...", "search");
            if (hasMoreGlobal && !isFetchingMoreRef.current) {
                isFetchingMoreRef.current = true;
                getGlobalShowcaseImages(true, 'similar_fetch').finally(() => {
                    isFetchingMoreRef.current = false;
                });
            }
            return;
        }

        // Track new items
        similarPicks.forEach(r => seenIdsRef.current.add(r.id));

        // Keep current, add similar after
        const currentImg = images[currentIndex];
        setImages([currentImg, ...similarPicks]);
        setCurrentIndex(0);

        if (containerRef.current) {
            containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
        }

        showToast(`✨ ${similarPicks.length} similar picks!`, "sparkles");
    }, [currentIndex, images, visibleGlobalCache, globalShowcaseCache.length, hasMoreGlobal, getGlobalShowcaseImages, showToast]);


    // 6. Aggressive Preloading
    useEffect(() => {
        if (!images.length) return;

        // Preload next 10 images
        const nextImages = images.slice(currentIndex + 1, currentIndex + 11);
        nextImages.forEach(img => {
            const link = document.createElement('link');
            link.rel = 'preload';
            link.as = 'image';
            link.href = getOptimizedImageUrl(img.url);
            document.head.appendChild(link);

            const i = new Image();
            i.src = getOptimizedImageUrl(img.url);
        });
    }, [currentIndex, images]);


    // 7. Trim history to prevent memory bloat
    useEffect(() => {
        if (seenIdsRef.current.size > HISTORY_CAP * 2) {
            const arr = Array.from(seenIdsRef.current);
            seenIdsRef.current = new Set(arr.slice(-HISTORY_CAP));
        }
    }, [images, currentIndex]);


    // Loading State
    if (loading && images.length === 0) {
        return (
            <div className="showcase-detail-container vertical-feed-mode flex flex-col items-center justify-center">
                <div className="loading-spinner-container">
                    <Sparkles className="animate-pulse text-purple-500" size={32} />
                    <p className="ml-3 text-gray-400">Loading feed...</p>
                </div>
            </div>
        );
    }

    if (images.length === 0) {
        return (
            <div className="showcase-detail-container vertical-feed-mode flex flex-col items-center justify-center p-8 text-center">
                <Sparkles size={48} className="text-purple-400 mb-4" />
                <h2 className="text-2xl font-bold mb-2">End of the Hive</h2>
                <button onClick={() => navigate('/discovery')} className="btn-primary-action mt-4">
                    Back to Discovery
                </button>
            </div>
        );
    }

    const currentItem = images[currentIndex];

    return (
        <div className="showcase-detail-container vertical-feed-mode">
            <SEO
                title={currentItem ? `${currentItem.prompt?.slice(0, 50)}... | Discovery - DreamBees` : 'Showcase | Discovery - DreamBees'}
                description={currentItem ? `AI-generated artwork: "${currentItem.prompt}". Explore more creative designs on DreamBees.` : "Infinite AI Art Feed - Explore community-generated masterpieces."}
                image={currentItem ? (currentItem.url || currentItem.imageUrl) : undefined}
                canonical={currentItem ? `/discovery/${slugify(currentItem.prompt?.slice(0, 40) || 'artwork')}--${currentItem.id}` : `/discovery/${id}`}
                structuredData={{
                    "@context": "https://schema.org",
                    "@graph": [
                        {
                            "@type": "VisualArtwork",
                            "name": currentItem ? (currentItem.prompt?.slice(0, 60) || "AI Artwork") : "AI Artwork",
                            "description": currentItem?.prompt || "AI-generated artwork on DreamBees.",
                            "image": currentItem ? (currentItem.url || currentItem.imageUrl) : undefined,
                            "creator": {
                                "@type": "Organization",
                                "name": "DreamBeesAI"
                            },
                            "artworkSurface": "Digital",
                            "artMedium": "AI Generated"
                        },
                        {
                            "@type": "BreadcrumbList",
                            "itemListElement": [
                                { "@type": "ListItem", "position": 1, "name": "Home", "item": "https://dreambeesai.com" },
                                { "@type": "ListItem", "position": 2, "name": "Discover", "item": "https://dreambeesai.com/discovery" },
                                { "@type": "ListItem", "position": 3, "name": "Artwork", "item": `https://dreambeesai.com/discovery/${currentItem ? slugify(currentItem.prompt?.slice(0, 40) || 'artwork') + '-' + currentItem.id : id}` }
                            ]
                        }
                    ]
                }}
            />

            {/* Fixed Nav Header (Transparent overlay) */}
            <header className="feed-nav-header">
                <button onClick={() => navigate('/discovery')} className="nav-back-blur">
                    <ArrowLeft size={20} />
                </button>

                {/* Shuffle Button */}
                <button
                    onClick={handleShuffle}
                    className="nav-shuffle-btn"
                    title="Shuffle feed for fresh content"
                >
                    <Shuffle size={18} />
                </button>
            </header>

            {/* Toast Notification */}
            <AnimatePresence>
                {shuffleToast && (
                    <motion.div
                        className="shuffle-toast"
                        initial={{ opacity: 0, y: 20, scale: 0.9 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: -20, scale: 0.9 }}
                        transition={{ duration: 0.3 }}
                    >
                        {shuffleToast.icon === 'shuffle' && <Shuffle size={18} />}
                        {shuffleToast.icon === 'refresh' && <RefreshCw size={18} className="animate-spin" />}
                        {shuffleToast.icon === 'sparkles' && <Sparkles size={18} />}
                        <span>{shuffleToast.message}</span>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Scroll Container */}
            <div
                className="vertical-feed-scroll-container"
                ref={containerRef}
            >
                {images.map((img, idx) => (
                    <FeedItem
                        key={`${img.id}-${idx}`}
                        image={img}
                        index={idx}
                        isActive={idx === currentIndex}
                        isLiked={isLiked(img.id)}
                        onToggleLike={() => {
                            const model = availableModels?.find(m => m.id === img.modelId);
                            toggleLike(img, model);
                        }}
                        onHide={() => {
                            hidePost(img);
                            // Remove from local list to animate out/snap to next
                            setImages(prev => prev.filter(i => i.id !== img.id));
                        }}
                        onMoreLikeThis={handleMoreLikeThis}
                        modelName={availableModels?.find(m => m.id === img.modelId)?.name}
                        navigate={navigate}
                    />
                ))}

                {/* Loader at bottom */}
                <div className="feed-end-message">
                    {hasMoreGlobal ? (
                        <div className="loading-spinner-container">
                            <RefreshCw className="animate-spin text-purple-500" size={24} />
                        </div>
                    ) : (
                        <div className="p-8 text-center opacity-50">
                            <p>You've seen it all!</p>
                            <button onClick={() => navigate('/discovery')} className="mt-4 underline">Reset</button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
});


// Sub-component for individual feed pages
const FeedItem = React.memo(function FeedItem({ image, index, isActive, isLiked, onToggleLike, onHide, onMoreLikeThis, modelName, navigate }) {
    // Generate deterministic slug for this specific item
    const currentSlug = slugify(image.prompt?.slice(0, 40) || 'artwork');
    const deterministicUrl = `${window.location.origin}/discovery/${currentSlug}-${image.id}`;

    // Double tap logic
    const lastTap = useRef(0);
    const [showHeartAnim, setShowHeartAnim] = useState(false);

    // Incremental Update Logic: Capture initial state to track local offsets
    const [initialLiked] = useState(() => isLiked);
    const [initialLikesCount] = useState(() => image.likesCount || image.likes || 0);

    // Derived Display Count
    const displayLikesCount = initialLikesCount + (isLiked ? 1 : 0) - (initialLiked ? 1 : 0);

    const handleImageClick = () => {
        const now = Date.now();
        if (now - lastTap.current < 300) {
            // Double tap detected
            if (!isLiked) onToggleLike();
            setShowHeartAnim(true);
            setTimeout(() => setShowHeartAnim(false), 1000);
        }
        lastTap.current = now;
    };

    // Extract display tags from the V2 metadata schema
    const displayTags = useMemo(() => {
        const tags = [];

        // Style primary
        if (image.style?.primary) {
            tags.push({ label: image.style.primary, type: 'style' });
        }

        // Vibe mood
        if (image.vibe?.mood) {
            tags.push({ label: image.vibe.mood, type: 'mood' });
        }

        // Subject category
        if (image.subject?.category) {
            tags.push({ label: image.subject.category, type: 'subject' });
        }

        // Style sub-genre
        if (image.style?.subGenre) {
            tags.push({ label: image.style.subGenre, type: 'genre' });
        }

        // Limit to 4 tags max
        return tags.slice(0, 4);
    }, [image]);

    return (
        <div className="feed-item" data-index={index}>
            {/* Main Visual */}
            <div className="feed-item-image-wrapper" onClick={handleImageClick}>
                <img
                    src={getOptimizedImageUrl(image.url)}
                    alt={image.prompt}
                    className="feed-image"
                    loading={Math.abs(index - isActive) < 5 ? "eager" : "lazy"}
                    decoding="async"
                    onError={(e) => {
                        e.target.style.display = 'none';
                        // Optional: You could also set e.target.src to a placeholder
                    }}
                />

                {/* Double Tap Heart Animation */}
                {showHeartAnim && (
                    <motion.div
                        className="double-tap-heart"
                        initial={{ scale: 0, opacity: 0 }}
                        animate={{ scale: 1.2, opacity: 1 }}
                        exit={{ scale: 1.5, opacity: 0 }}
                        transition={{ duration: 0.4, ease: "easeOut" }}
                    >
                        <Heart size={80} fill="white" />
                    </motion.div>
                )}

                {/* Overlays */}
                <div className="feed-top-gradient" />
                <div className="feed-overlay-gradient" />
            </div>

            {/* Right Action Sidebar */}
            <div className="feed-actions-sidebar">
                <div className="action-btn-wrapper">
                    <button className={`action-btn ${isLiked ? 'active' : ''}`} onClick={(e) => {
                        e.stopPropagation();
                        onToggleLike();
                    }}>
                        <Heart size={26} className={isLiked ? 'fill-current' : ''} />
                    </button>
                    <span className="action-label">{displayLikesCount}</span>
                </div>

                <div className="action-btn-wrapper">
                    <button className="action-btn" onClick={(e) => {
                        e.stopPropagation();
                        navigator.clipboard.writeText(deterministicUrl);
                        toast.success("Link copied!");
                    }}>
                        <Share2 size={24} />
                    </button>
                    <span className="action-label">Share</span>
                </div>

                <div className="action-btn-wrapper">
                    <button className="action-btn" onClick={(e) => {
                        e.stopPropagation();
                        onMoreLikeThis?.();
                    }} title="More like this">
                        <Sparkles size={24} />
                    </button>
                    <span className="action-label">Similar</span>
                </div>

                <div className="action-btn-wrapper">
                    <button className="action-btn" onClick={(e) => {
                        e.stopPropagation();
                        onHide?.();
                    }} title="Hide this post">
                        <Flag size={24} />
                    </button>
                    <span className="action-label">Hide</span>
                </div>
            </div>

            {/* Bottom Info Area */}
            <div className="feed-info-area">
                <div className="feed-info-content">
                    {modelName && (
                        <div className="model-pill" onClick={() => navigate(`/model/${image.modelId}`)}>
                            @{modelName}
                        </div>
                    )}

                    <p className="prompt-text">
                        {image.prompt || image.subject?.details || 'AI Generated Art'}
                    </p>

                    {/* Enhanced Tags Display */}
                    <div className="tags-row">
                        {displayTags.map((tag, i) => (
                            <span
                                key={`${tag.label}-${i}`}
                                className={`feed-tag feed-tag-${tag.type}`}
                            >
                                #{tag.label.replace(/\s+/g, '')}
                            </span>
                        ))}

                        {/* Color palette indicator */}
                        {image.colors?.dominant && (
                            <div className="palette-dots">
                                {(image.colors?.dominant || []).slice(0, 3).map((color, i) => (
                                    <span
                                        key={i}
                                        className="palette-dot"
                                        style={{ backgroundColor: color }}
                                    />
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
});

export default ShowcaseDetail;

import React, { useState, useEffect, useRef } from 'react';
import SEO from '../components/SEO';
import { useAuth } from '../contexts/AuthContext';
import { db } from '../firebase';
// import { httpsCallable } from 'firebase/functions'; // Removed
import { useApi } from '../hooks/useApi';
import { doc, onSnapshot } from 'firebase/firestore';
import toast from 'react-hot-toast';
import { Button } from '../components/Slideshow/Button';
import { ImageUploader } from '../components/Slideshow/ImageUploader';
import { Sparkles, Download, Languages, Presentation, Image as ImageIcon, Loader2, ArrowLeft, Wand2, FileImage, Gem, ChevronLeft, ChevronRight, RefreshCw } from 'lucide-react';
import { Link } from 'react-router-dom';
import { compressImage } from '../utils';
import { useUserInteractions } from '../contexts/UserInteractionsContext';
import './Slideshow.css';

const LOADING_MESSAGES = [
    "Summoning Nekomimi guides...",
    "Analyzing image structure...",
    "Designing kawaii layout...",
    "Simplifying concepts for kids...",
    "Drawing cute diagrams...",
    "Mixing pastel colors...",
    "Adding educational sparkles...",
    "Polishing vector lines...",
    "Finalizing the magic..."
];

export default function Slideshow() {
    const { currentUser } = useAuth();
    const { userProfile, deductZapsOptimistically, rollbackZaps } = useUserInteractions();
    const zaps = userProfile?.zaps || 0;

    // Steps: 'upload' | 'processing' | 'result'
    const [currentStep, setCurrentStep] = useState('upload');

    // State
    const [selectedFile, setSelectedFile] = useState(null);
    const [previewUrl, setPreviewUrl] = useState(null);
    const [loadingMessage, setLoadingMessage] = useState(LOADING_MESSAGES[0]);
    const [progress, setProgress] = useState(0);
    const [results, setResults] = useState([]);
    const [requestId, setRequestId] = useState(null);
    const [activeSlideIndex, setActiveSlideIndex] = useState(0);
    // history state removed

    // Settings
    const [language, setLanguage] = useState('English');
    const [mode, setMode] = useState('poster');

    const isMounted = useRef(true);
    useEffect(() => {
        isMounted.current = true;
        return () => { isMounted.current = false; };
    }, []);

    const handleImageSelect = (file, url) => {
        setSelectedFile(file);
        setPreviewUrl(url);
    };

    const _handleClear = () => {
        setSelectedFile(null);
        setPreviewUrl(null);
    };

    // Cleanup preview blob
    useEffect(() => {
        return () => {
            if (previewUrl && previewUrl.startsWith('blob:')) {
                URL.revokeObjectURL(previewUrl);
            }
        };
    }, [previewUrl]);

    // Cycle loading messages

    // Cycle loading messages
    useEffect(() => {
        if (currentStep !== 'processing') return;
        let index = 0;
        const interval = setInterval(() => {
            index = (index + 1) % LOADING_MESSAGES.length;
            setLoadingMessage(LOADING_MESSAGES[index]);
        }, 2000);
        return () => clearInterval(interval);
    }, [currentStep]);

    const { call: apiCall } = useApi();

    const handleGenerate = async () => {
        if (!selectedFile) return toast.error("Please select an image first");
        if (!currentUser) return toast.error("Please sign in to generate");

        const cost = mode === 'slideshow' ? 3 : 0.5;
        if (zaps < cost) {
            toast.error(`Insufficient Zaps ⚡ (Need ${cost})`);
            return;
        }

        const requestId = `ss_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;
        deductZapsOptimistically(cost, requestId);
        setCurrentStep('processing');
        setProgress(5);
        setResults([]);
        setActiveSlideIndex(0);

        try {
            let imageBase64 = null;
            if (previewUrl) {
                // Compress client-side
                imageBase64 = await compressImage(previewUrl, 1536, 0.85);
            }

            // const api = httpsCallable(functions, 'api', { timeout: 540000 });
            const { data } = await apiCall('api', {
                action: 'createSlideshowGeneration',
                image: imageBase64,
                mode: mode,
                language: language,
                requestId
            }, {
                timeout: 540000,
                toastErrors: true
            });

            if (isMounted.current) {
                const finalRequestId = data.requestId || requestId;
                setRequestId(finalRequestId);
                localStorage.setItem('slideshowState', JSON.stringify({ requestId: finalRequestId, mode }));
            }

        } catch (error) {
            console.error("Generation failed:", error);
            const cost = mode === 'slideshow' ? 3 : 0.5;
            rollbackZaps(cost, typeof requestId !== 'undefined' ? requestId : 'legacy');
            if (isMounted.current) {
                // toast handled by useApi
                setCurrentStep('upload');
            }
        }
    };

    // Restore state on mount
    useEffect(() => {
        const saved = localStorage.getItem('slideshowState');
        if (saved) {
            try {
                const { requestId: savedId, mode: savedMode } = JSON.parse(saved);
                if (savedId) {
                    console.log("Restoring slideshow session:", savedId);
                    setRequestId(savedId);
                    setMode(savedMode || 'poster'); // Restore mode if saved
                    setCurrentStep('processing');
                }
            } catch (err) {
                console.warn("Failed to parse saved slideshow session:", err);
                localStorage.removeItem('slideshowState'); // Clean up bad data
            }
        }
    }, []);

    // Poll for results
    useEffect(() => {
        if (!requestId) return;

        console.log("[Slideshow] Starting listener for ID:", requestId);

        const unsubscribe = onSnapshot(doc(db, 'generation_queue', requestId), (snapshot) => {
            if (!snapshot.exists()) return;
            const data = snapshot.data();

            // Safety check for unmounted
            if (!isMounted.current) return;

            if (data.status === 'processing') {
                // Use functional update to avoid dependency on results
                // AND use refs for mode if needed, but here simple calculation is fine
                setResults(prevResults => {
                    // Only update if actually different to save renders
                    if (JSON.stringify(prevResults) !== JSON.stringify(data.results)) {
                        return data.results || [];
                    }
                    return prevResults;
                });

                // Live Streaming: Switch to result view if we have at least one result
                // Use functional update for step to avoid dependency
                setCurrentStep(prevStep => {
                    if ((data.results?.length || 0) > 0 && prevStep === 'processing') {
                        return 'result';
                    }
                    return prevStep;
                });

                const completed = data.results ? data.results.length : 0;
                if (completed > 0) {
                    // We can't easily access 'mode' here without a ref if we want to be pure,
                    // but 'total' is just for display.
                    // A cleaner way is to just set it based on what we know or just generic text.
                    // But actually, we can use a ref for 'mode' if we really need it,
                    // or just omit it from deps and accept it might be stale if it changed (which it shouldn't during gen).
                    // However, to be safe and clean:
                    setLoadingMessage(`Generating images... (${completed} completed)`);
                }

            } else if (data.status === 'completed') {
                setResults(data.results || []);
                setProgress(100);
                setCurrentStep('result');

                // Only stop listening when fully completed
                setTimeout(() => {
                    if (isMounted.current) {
                        setRequestId(null);
                        localStorage.removeItem('slideshowState');
                    }
                }, 1000);

            } else if (data.status === 'failed') {
                toast.error(`Failed: ${data.error}`);
                setCurrentStep('upload');
                setRequestId(null);
                localStorage.removeItem('slideshowState');
            }
        }, (error) => {
            console.error("Slideshow listener error:", error);
        });

        return () => {
            console.log("[Slideshow] Unsubscribing listener for ID:", requestId);
            unsubscribe();
        };
    }, [requestId]); // Only depend on requestId


    // Zeno's Progress Simulation
    useEffect(() => {
        if (currentStep !== 'processing') return;

        const interval = setInterval(() => {
            setProgress(prev => {
                const total = mode === 'slideshow' ? 8 : 1;
                const completed = results.length;
                const segmentSize = 80 / total;
                const base = 10;

                // Target: Start of current segment + 90% of that segment
                const currentTarget = base + (completed * segmentSize) + (segmentSize * 0.9);
                const actualTarget = Math.min(currentTarget, 95);

                if (prev >= actualTarget) return prev;

                const distance = actualTarget - prev;
                // Move 10% of the remaining distance or min 0.1
                const step = Math.max(0.05, distance * 0.05);

                return Math.min(prev + step, 98);
            });
        }, 100);

        return () => clearInterval(interval);
    }, [currentStep, results.length, mode]);

    const handleDownloadCurrent = async () => {
        if (results.length === 0) return;
        const current = results[activeSlideIndex];
        downloadImage(current.imageUrl, activeSlideIndex);
    };

    const handleDownloadAll = async () => {
        results.forEach((res, idx) => {
            downloadImage(res.imageUrl, idx);
        });
    };

    const downloadImage = async (url, index) => {
        try {
            const controller = new AbortController();
            const timeoutId = setTimeout(() => controller.abort(), 30000); // 30s timeout for download
            const response = await fetch(url, { signal: controller.signal });
            clearTimeout(timeoutId);
            if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
            const blob = await response.blob();
            const blobUrl = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = blobUrl;
            link.download = `nekomimi-${mode}-${index + 1}.webp`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            window.URL.revokeObjectURL(blobUrl);
        } catch (e) {
            console.error("Download error:", e);
            toast.error("Download failed due to network error");
        }
    };

    return (
        <div className="slideshow-page">
            <SEO
                title="Slideshow Magic - AI Educational Art Creator"
                description="Transform your images into professional Nekomimi educational posters or interactive slideshows using advanced AI."
                structuredData={{
                    "@context": "https://schema.org",
                    "@graph": [
                        {
                            "@type": "Service",
                            "name": "DreamBeesAI Slideshow Magic",
                            "description": "Educational AI art transformation service.",
                            "provider": {
                                "@type": "Organization",
                                "name": "DreamBeesAI"
                            },
                            "offers": {
                                "@type": "Offer",
                                "price": "0.50",
                                "priceCurrency": "USD",
                                "description": "0.5 Zaps per poster transformation."
                            }
                        },
                        {
                            "@type": "SoftwareApplication",
                            "name": "DreamBeesAI Slideshow Magic",
                            "applicationCategory": "EducationalApplication",
                            "operatingSystem": "Web",
                            "offers": {
                                "@type": "Offer",
                                "price": "0.00",
                                "priceCurrency": "USD"
                            }
                        }
                    ]
                }}
            />
            <div className="slideshow-container">

                {/* Steps */}
                <div className="step-indicator">
                    <span className={`step-pill ${currentStep === 'upload' ? 'active' : ''}`}>1. Source</span>
                    <span className="step-arrow">→</span>
                    <span className={`step-pill ${currentStep === 'processing' ? 'active' : ''}`}>2. Magic</span>
                    <span className="step-arrow">→</span>
                    <span className={`step-pill ${currentStep === 'result' ? 'active' : ''}`}>3. Result</span>
                </div>

                {/* STEP 1: UPLOAD */}
                {currentStep === 'upload' && (
                    <>
                        <div className="hero-text">
                            <div className="powered-badge">
                                <Gem size={12} /> POWERED BY GEMINI 3 PRO
                            </div>
                            <h1 className="hero-title">
                                Turn ideas into <br />
                                <span className="gradient-text">Kawaii Educational Art</span>
                            </h1>
                            <p className="hero-description">
                                Upload an image to transform it into a professional Nekomimi children's educational poster or slideshow.
                            </p>
                        </div>

                        <div className="main-card">
                            <div className="card-padding">
                                <ImageUploader
                                    selectedImage={previewUrl}
                                    onImageSelect={handleImageSelect}
                                />

                                <div className="input-grid">
                                    <div className="input-field">
                                        <label className="input-label">Format</label>
                                        <div className="segment-control">
                                            <button
                                                className={`segment-btn ${mode === 'poster' ? 'active' : ''}`}
                                                onClick={() => setMode('poster')}
                                            >
                                                <FileImage size={16} /> Poster
                                            </button>
                                            <button
                                                className={`segment-btn ${mode === 'slideshow' ? 'active' : ''}`}
                                                onClick={() => setMode('slideshow')}
                                            >
                                                <Presentation size={16} /> Slideshow
                                            </button>
                                        </div>
                                    </div>

                                    <div className="input-field">
                                        <label className="input-label">Language</label>
                                        <div className="select-wrapper">
                                            <Languages size={16} className="text-zinc-500 mr-2" />
                                            <select
                                                value={language}
                                                onChange={(e) => setLanguage(e.target.value)}
                                                className="native-select"
                                            >
                                                {['English', 'Spanish', 'French', 'German', 'Japanese', 'Korean', 'Chinese'].map(lang => (
                                                    <option key={lang} value={lang} style={{ background: '#27272a' }}>{lang}</option>
                                                ))}
                                            </select>
                                        </div>
                                    </div>
                                </div>

                                <Button
                                    onClick={handleGenerate}
                                    disabled={!selectedFile || zaps < (mode === 'slideshow' ? 3 : 0.5)}
                                    title={zaps < (mode === 'slideshow' ? 3 : 0.5) ? "Insufficient Zaps ⚡" : ""}
                                    className="w-full"
                                    icon={Wand2}
                                >
                                    {mode === 'poster' ? 'Transform with Magic (0.5 Credits)' : 'Generate Slideshow (3 Credits)'}
                                </Button>
                            </div>
                        </div>


                    </>
                )}

                {/* STEP 2: PROCESSING */}
                {currentStep === 'processing' && (
                    <div className="processing-view">
                        <div className="magic-portal">
                            <div className="portal-ring-1" />
                            <div className="portal-ring-2" />
                            <div className="portal-pulse" />
                            <div className="portal-icon">
                                <Sparkles size={48} />
                            </div>
                        </div>

                        <h2 className="text-2xl font-bold text-white mb-4">Creating Magic...</h2>
                        <div className="progress-bar-container">
                            <div className="progress-fill" style={{ width: `${progress}%` }} />
                        </div>
                        <p className="text-zinc-400 font-medium animate-pulse">
                            {loadingMessage}
                        </p>
                    </div>
                )}

                {/* STEP 3: RESULT */}
                {currentStep === 'result' && results.length > 0 && (
                    <div className="main-card">
                        <div className="card-padding">
                            <div className="result-header">
                                <div className="flex items-center gap-4">
                                    <Button variant="secondary" onClick={() => setCurrentStep('upload')} icon={ArrowLeft} className="!w-auto">
                                        Create New
                                    </Button>
                                    {requestId && (
                                        <div className="flex items-center gap-2 text-brand-400 text-sm font-medium animate-pulse">
                                            <Loader2 size={16} className="animate-spin" />
                                            Generating...
                                        </div>
                                    )}
                                </div>
                                <div className="flex gap-2">
                                    {mode === 'slideshow' ? (
                                        <Button onClick={handleDownloadAll} icon={Download} className="!w-auto">
                                            Download All
                                        </Button>
                                    ) : (
                                        <Button onClick={handleDownloadCurrent} icon={Download} className="!w-auto">
                                            Download
                                        </Button>
                                    )}
                                </div>
                            </div>

                            <div className="primary-result-box">
                                {results[activeSlideIndex].imageUrl ? (
                                    <img
                                        src={results[activeSlideIndex].imageUrl}
                                        alt="Result"
                                        className="main-image"
                                    />
                                ) : (
                                    <div className="main-image placeholder-slide">
                                        <div className="placeholder-content">
                                            <Loader2 size={48} className="animate-spin text-brand-400 mb-4" />
                                            <h3 className="text-xl font-bold text-white mb-2">Painting Slide {activeSlideIndex + 1}...</h3>
                                            <p className="text-zinc-400 text-center max-w-md">
                                                {results[activeSlideIndex].prompt || "Mixing magic colors..."}
                                            </p>
                                        </div>
                                    </div>
                                )}

                                {results.length > 1 && (
                                    <>
                                        <button
                                            className="nav-btn nav-prev"
                                            disabled={activeSlideIndex === 0}
                                            onClick={() => setActiveSlideIndex(i => Math.max(0, i - 1))}
                                        >
                                            <ChevronLeft />
                                        </button>
                                        <button
                                            className="nav-btn nav-next"
                                            disabled={activeSlideIndex === results.length - 1}
                                            onClick={() => setActiveSlideIndex(i => Math.min(results.length - 1, i + 1))}
                                        >
                                            <ChevronRight />
                                        </button>
                                    </>
                                )}
                            </div>

                            {results.length > 1 && (
                                <div className="thumbnails-track">
                                    {results.map((res, idx) => (
                                        <div
                                            key={idx}
                                            className={`thumbnail-btn ${activeSlideIndex === idx ? 'active' : ''}`}
                                            onClick={() => setActiveSlideIndex(idx)}
                                        >
                                            {res.imageUrl ? (
                                                <img src={res.imageUrl} className="thumbnail-img" />
                                            ) : (
                                                <div className="thumbnail-img placeholder-thumbnail">
                                                    <Loader2 size={16} className="animate-spin text-zinc-500" />
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            )}

                        </div>
                    </div>
                )}

            </div>
        </div>
    );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate, useLocation, useSearchParams } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { db } from '../firebase';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Heart,
    Bookmark,
    Edit2,
    AlertCircle,
    ChevronLeft,
    ChevronRight,
    X,
    Lock,
    ExternalLink,
    ArrowRight,
    Sparkles,
    RefreshCw,
    Download,
    PanelRightClose,
    PanelRightOpen
} from 'lucide-react';
import { toast } from 'react-hot-toast';
import html2canvas from 'html2canvas';
import SEO from '../components/SEO';
import { useUserInteractions } from '../contexts/UserInteractionsContext';
import { useModel } from '../contexts/ModelContext';
import { useIntersectionObserver } from '../hooks/useIntersectionObserver';
import './UserProfile.css';

const PAGE_SIZE = 20;

export default function UserProfile() {
    const { currentUser } = useAuth();
    const { likes, bookmarks, userProfile } = useUserInteractions();
    const navigate = useNavigate();
    const location = useLocation();

    const [isEditing, setIsEditing] = useState(false);
    const [savingProfile, setSavingProfile] = useState(false);
    const [usernameError, setUsernameError] = useState(null);
    const [editForm, setEditForm] = useState({
        username: '',
        displayPreference: 'username'
    });

    // Determine active tab from URL path
    const activeTab = location.pathname.includes('/saved') ? 'saved' : 'liked';
    const displayedItems = activeTab === 'liked' ? likes : bookmarks;

    // Pagination/Lazy Load state
    const [visibleCount, setVisibleCount] = useState(PAGE_SIZE);
    const visibleItems = displayedItems.slice(0, visibleCount);
    const isPagingRef = useRef(false);

    // Setup intersection observer for "Load More"
    const { ref: loadMoreRef, entry } = useIntersectionObserver({
        threshold: 0.1,
        rootMargin: '200px',
    });

    useEffect(() => {
        if (!entry?.isIntersecting) {
            isPagingRef.current = false;
            return;
        }

        if (isPagingRef.current) return;
        if (visibleCount >= displayedItems.length) return;

        isPagingRef.current = true;
        setVisibleCount(prev => prev + PAGE_SIZE);
    }, [entry?.isIntersecting, displayedItems.length, visibleCount]);

    useEffect(() => {
        if (userProfile) {
            setEditForm({
                username: userProfile.username || '',
                displayPreference: userProfile.displayPreference || 'username'
            });
        }
    }, [userProfile]);

    const handleSaveProfile = async () => {
        if (!editForm.username) {
            setUsernameError('Username is required');
            return;
        }

        if (editForm.username.length < 3) {
            setUsernameError('Username must be at least 3 characters');
            return;
        }

        setSavingProfile(true);
        try {
            // Check if username is taken (if it changed)
            if (editForm.username !== userProfile?.username) {
                const usernameDoc = await getDoc(doc(db, 'usernames', editForm.username));
                if (usernameDoc.exists()) {
                    setUsernameError('Username is already taken');
                    setSavingProfile(false);
                    return;
                }
            }

            // Update profile
            await setDoc(doc(db, 'profiles', currentUser.uid), {
                ...editForm,
                updatedAt: new Date().toISOString()
            }, { merge: true });

            // Update username mapping
            if (editForm.username !== userProfile?.username) {
                await setDoc(doc(db, 'usernames', editForm.username), {
                    uid: currentUser.uid
                });
            }

            toast.success('Profile updated successfully');
            setIsEditing(false);
        } catch (error) {
            console.error('Error saving profile:', error);
            toast.error('Failed to update profile');
        } finally {
            setSavingProfile(false);
        }
    };

    const { availableModels } = useModel();
    const [searchParams, setSearchParams] = useSearchParams();
    const [selectedImage, setSelectedImage] = useState(null);
    const [isZoomed, setIsZoomed] = useState(false);
    const [showSidebar, setShowSidebar] = useState(true);
    const imageAreaRef = useRef(null);

    // Reset zoom when image changes
    useEffect(() => {
        setIsZoomed(false);
    }, [selectedImage]);

    // Filter focus logic: Handle deep linking ?view=ID
    useEffect(() => {
        const viewId = searchParams.get('view');
        if (viewId) {
            // Find in current items or fetch if needed
            const found = displayedItems.find(img => img.id === viewId || img.id.replace('show_', '') === viewId);
            if (found) {
                setSelectedImage(found);
            }
        } else {
            setSelectedImage(null);
        }
    }, [searchParams, displayedItems]);

    const openLightbox = useCallback((item) => {
        const id = item.id.replace('show_', '');
        setSearchParams(prev => {
            const next = new URLSearchParams(prev);
            next.set('view', id);
            return next;
        });
    }, [setSearchParams]);

    const closeLightbox = useCallback(() => {
        setSearchParams(prev => {
            const next = new URLSearchParams(prev);
            next.delete('view');
            return next;
        });
    }, [setSearchParams]);

    const handleNavigate = useCallback((direction) => {
        if (!selectedImage || displayedItems.length === 0) return;

        const currentIndex = displayedItems.findIndex(item => item.id === selectedImage.id);
        if (currentIndex === -1) return;

        let nextIndex = currentIndex + direction;

        // Wrap around
        if (nextIndex >= displayedItems.length) nextIndex = 0;
        if (nextIndex < 0) nextIndex = displayedItems.length - 1;

        const nextItem = displayedItems[nextIndex];
        openLightbox(nextItem);
    }, [selectedImage, displayedItems, openLightbox]);

    // Keyboard navigation
    useEffect(() => {
        if (!selectedImage) return;

        const handleKeyDown = (e) => {
            if (e.key === 'ArrowRight') handleNavigate(1);
            if (e.key === 'ArrowLeft') handleNavigate(-1);
            if (e.key === 'Escape') closeLightbox();
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [selectedImage, handleNavigate, closeLightbox]); // Re-bind when selection or list changes

    const getOptimizedImageUrl = (url) => {
        if (!url) return '';
        if (url.includes('firebasestorage.googleapis.com')) return url;
        // Logic for Cloudflare image re-optimization if needed
        return url;
    };

    if (!currentUser) {
        return (
            <div className="up-page-restricted">
                <div className="up-modal text-center">
                    <AlertCircle className="mx-auto" size={48} style={{ color: 'var(--studio-text-muted)', marginBottom: '24px' }} />
                    <h2 style={{ marginBottom: '8px' }}>Access Restricted</h2>
